function countLiveNeighbors(
  livingCells: Set<string>,
  x: number,
  y: number
): number {
  let neighbors = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (livingCells.has(`${x + dx},${y + dy}`)) neighbors++;
    }
  }
  return neighbors;
}

export function nextGeneration(livingCells: Set<string>): Set<string> {
  const result = new Set<string>();
  for (const cell of livingCells) {
    const [x, y] = cell.split(",").map(Number);
    const liveNeighborCount = countLiveNeighbors(livingCells, x, y);
    if (liveNeighborCount === 2 || liveNeighborCount === 3) result.add(cell);
  }
  return result;
}

