function countLiveNeighbors(
  livingCells: Set<string>,
  x: number,
  y: number
): number {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (livingCells.has(`${x + dx},${y + dy}`)) count++;
    }
  }
  return count;
}

function survives(liveNeighborCount: number): boolean {
  return liveNeighborCount === 2 || liveNeighborCount === 3;
}

export function nextGeneration(livingCells: Set<string>): Set<string> {
  const survivors = new Set<string>();
  for (const cell of livingCells) {
    const [x, y] = cell.split(",").map(Number);
    if (survives(countLiveNeighbors(livingCells, x, y))) survivors.add(cell);
  }
  return survivors;
}
